/* global Accelerometer, GravitySensor, Gyroscope, AbsoluteOrientationSensor */
import React, { useEffect, useState, useCallback } from "react";
import {
  Card,
  CardContent,
  Typography,
  Grid,
  Box,
  useTheme,
} from "@mui/material";
import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
} from "recharts";

const SENSOR_CONFIG = {
  maxLength: 100,
  frequency: 60,
};

const getColors = (mode) => ({
  x: mode === "dark" ? "#8884d8" : "#0000ff",
  y: mode === "dark" ? "#82ca9d" : "#008000",
  z: mode === "dark" ? "#ffc658" : "#ffcc00",
  w: mode === "dark" ? "#f54242" : "#ff0000",
  pitch: mode === "dark" ? "#8884d8" : "#0000ff",
  roll: mode === "dark" ? "#82ca9d" : "#008000",
  yaw: mode === "dark" ? "#ffc658" : "#ffcc00",
  compass: mode === "dark" ? "#8884d8" : "#0000ff",
});

const useSensors = () => {
  const [sensorData, setSensorData] = useState({});
  const [chartData, setChartData] = useState({});
  const [error, setError] = useState(null);

  const initializeSensors = useCallback((sensorType, keys, sensorInstance) => {
    setSensorData((prevData) => ({
      ...prevData,
      [sensorType]: { data: {}, max: {}, min: {} },
    }));
    setChartData((prevData) => ({ ...prevData, [sensorType]: [] }));

    sensorInstance.addEventListener("reading", () => {
      const newData = keys.reduce((data, key) => {
        data[key] = sensorInstance[key] || 0;
        return data;
      }, {});

      setSensorData((prevData) => {
        const updated = { ...prevData[sensorType] };
        Object.keys(newData).forEach((key) => {
          updated.max[key] = Math.max(
            updated.max[key] || -Infinity,
            newData[key]
          );
          updated.min[key] = Math.min(
            updated.min[key] || Infinity,
            newData[key]
          );
        });
        updated.data = newData;
        return { ...prevData, [sensorType]: updated };
      });

      setChartData((prevData) => {
        const updatedData = [
          ...prevData[sensorType],
          { ...newData, timestamp: Date.now() },
        ];
        return {
          ...prevData,
          [sensorType]: updatedData.slice(-SENSOR_CONFIG.maxLength),
        };
      });
    });

    sensorInstance.start();
    return () => sensorInstance.stop();
  }, []);

  useEffect(() => {
    const sensorsCleanup = [];

    const setupOrientationSensor = () => {
      const handleOrientationEvent = ({ alpha, beta, gamma }) => {
        if (alpha != null && beta != null && gamma != null) {
          const inclinometerData = { pitch: beta, roll: gamma, yaw: alpha };
          const compassData = { compass: 360 - alpha };

          setSensorData((prevData) => {
            const updatedInclinometer = { ...prevData.inclinometer };
            const updatedCompass = { ...prevData.compass };

            Object.assign(updatedInclinometer, {
              data: inclinometerData,
              max: {
                pitch: Math.max(
                  inclinometerData.pitch,
                  updatedInclinometer.max?.pitch || -Infinity
                ),
                roll: Math.max(
                  inclinometerData.roll,
                  updatedInclinometer.max?.roll || -Infinity
                ),
                yaw: Math.max(
                  inclinometerData.yaw,
                  updatedInclinometer.max?.yaw || -Infinity
                ),
              },
              min: {
                pitch: Math.min(
                  inclinometerData.pitch,
                  updatedInclinometer.min?.pitch || Infinity
                ),
                roll: Math.min(
                  inclinometerData.roll,
                  updatedInclinometer.min?.roll || Infinity
                ),
                yaw: Math.min(
                  inclinometerData.yaw,
                  updatedInclinometer.min?.yaw || Infinity
                ),
              },
            });

            Object.assign(updatedCompass, {
              data: compassData,
              max: {
                compass: Math.max(
                  compassData.compass,
                  updatedCompass.max?.compass || -Infinity
                ),
              },
              min: {
                compass: Math.min(
                  compassData.compass,
                  updatedCompass.min?.compass || Infinity
                ),
              },
            });

            return {
              ...prevData,
              inclinometer: updatedInclinometer,
              compass: updatedCompass,
            };
          });
        }
      };

      window.addEventListener("deviceorientation", handleOrientationEvent);
      return () =>
        window.removeEventListener("deviceorientation", handleOrientationEvent);
    };

    sensorsCleanup.push(setupOrientationSensor());

    if (window.Accelerometer) {
      try {
        const accelerometer = new Accelerometer({
          frequency: SENSOR_CONFIG.frequency,
        });
        sensorsCleanup.push(
          initializeSensors("accelerometer", ["x", "y", "z"], accelerometer)
        );
      } catch (err) {
        setError("Accelerometer not supported or permission denied");
      }
    }

    if (window.GravitySensor) {
      try {
        const gravity = new GravitySensor({
          frequency: SENSOR_CONFIG.frequency,
        });
        sensorsCleanup.push(
          initializeSensors("gravity", ["x", "y", "z"], gravity)
        );
      } catch (err) {
        setError("GravitySensor not supported or permission denied");
      }
    }

    if (window.Gyroscope) {
      try {
        const gyroscope = new Gyroscope({ frequency: SENSOR_CONFIG.frequency });
        sensorsCleanup.push(
          initializeSensors("gyroscope", ["x", "y", "z"], gyroscope)
        );
      } catch (err) {
        setError("Gyroscope not supported or permission denied");
      }
    }

    if (window.AbsoluteOrientationSensor) {
      try {
        const orientation = new AbsoluteOrientationSensor({
          frequency: SENSOR_CONFIG.frequency,
        });
        sensorsCleanup.push(
          initializeSensors("orientation", ["x", "y", "z", "w"], orientation)
        );
      } catch (err) {
        setError(
          "AbsoluteOrientationSensor not supported or permission denied"
        );
      }
    }

    return () => sensorsCleanup.forEach((cleanup) => cleanup());
  }, [initializeSensors]);

  return { sensorData, chartData, error };
};

const SensorChart = ({ data, colors }) => (
  <Box sx={{ height: 250 }}>
    <ResponsiveContainer width="100%" height="100%">
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="timestamp" hide />
        <YAxis />
        <Tooltip transitionDuration={0} />
        {Object.keys(data[0] || {}).map(
          (key) =>
            key !== "timestamp" && (
              <Line
                key={key}
                type="monotone"
                dataKey={key}
                stroke={colors[key]}
                isAnimationActive={false}
                dot={false}
                strokeWidth={2}
              />
            )
        )}
      </LineChart>
    </ResponsiveContainer>
  </Box>
);

const SensorSection = ({ sensorData, chartData }) => {
  const theme = useTheme();
  const colors = getColors(theme.palette.mode);

  return (
    <>
      {Object.entries(sensorData).map(([sensorType, { data, max, min }]) => (
        <Grid item xs={12} md={6} lg={4} key={sensorType}>
          <Card sx={{ height: 500 }}>
            <CardContent>
              <Typography variant="h6">{sensorType.toUpperCase()}</Typography>
              {Object.entries(data).map(([key, value]) => (
                <Typography key={key} color={colors[key]}>
                  {`${key.toUpperCase()}: ${value.toFixed(2)} (Max: ${max[
                    key
                  ]?.toFixed(2)}, Min: ${min[key]?.toFixed(2)})`}
                </Typography>
              ))}
            </CardContent>
            <SensorChart data={chartData[sensorType]} colors={colors} />
          </Card>
        </Grid>
      ))}
    </>
  );
};

const SensorPage = () => {
  const { sensorData, chartData, error } = useSensors();
  return (
    <Grid container spacing={4} sx={{ py: 4, px: 2 }}>
      {error ? (
        <Grid item xs={12}>
          <Typography color="error">{error}</Typography>
        </Grid>
      ) : (
        <SensorSection sensorData={sensorData} chartData={chartData} />
      )}
    </Grid>
  );
};

export default SensorPage;
